import React from 'react';
import { Box, Paper, Typography, Chip, Avatar } from '@mui/material';
import { DragDropContext, Droppable, Draggable } from '@hello-pangea/dnd';

const reorder = (list, startIndex, endIndex) => {
  const result = Array.from(list);
  const [removed] = result.splice(startIndex, 1);
  result.splice(endIndex, 0, removed);
  return result;
};

export default function KanbanBoard({ columns, tasksByColumn, onMoveTask, currentUser, canDragTask, onReorderColumns }) {
  const handleDragEnd = (result) => {
    const { source, destination, draggableId, type } = result;
    if (!destination) return;

    // Handle column reordering
    if (type === 'COLUMN') {
      if (source.index !== destination.index) {
        onReorderColumns?.(source.index, destination.index);
      }
      return;
    }

    // Handle task dragging
    const sourceKey = source.droppableId;
    const destKey = destination.droppableId;

    if (sourceKey === destKey) {
      // reorder within same column
      onMoveTask(draggableId, { column: sourceKey, reorder: { from: source.index, to: destination.index } });
      return;
    }

    // moved across columns
    onMoveTask(draggableId, { column: destKey });
  };

  return (
    <DragDropContext onDragEnd={handleDragEnd}>
      <Droppable droppableId="all-columns" direction="horizontal" type="COLUMN">
        {(provided, snapshot) => (
          <Box
            ref={provided.innerRef}
            {...provided.droppableProps}
            sx={{ display: 'flex', gap: 2, alignItems: 'flex-start' }}
          >
            {columns.map((col, colIndex) => {
              const colKey = col.id ?? col.key;
              const tasks = tasksByColumn[colKey] || [];

              return (
                <Draggable key={String(colKey)} draggableId={`col-${colKey}`} index={colIndex} type="COLUMN">
                  {(dragProv, dragSnap) => (
                    <div ref={dragProv.innerRef} {...dragProv.draggableProps}>
                      <Droppable droppableId={String(colKey)} type="TASK">
                        {(provided, snapshot) => (
                          <Paper
                            ref={provided.innerRef}
                            {...provided.droppableProps}
                            elevation={snapshot.isDraggingOver ? 6 : 1}
                            sx={{
                              flex: 1,
                              minHeight: 240,
                              maxHeight: '70vh',
                              overflowY: 'auto',
                              p: 2,
                              backgroundColor: snapshot.isDraggingOver ? '#F0F9FF' : 'inherit',
                              opacity: dragSnap.isDragging ? 0.5 : 1,
                              cursor: 'grab',
                              transition: 'opacity 0.2s',
                            }}
                            {...dragProv.dragHandleProps}
                          >
                            <Box sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', mb: 2 }}>
                              <Typography variant="subtitle1" sx={{ fontWeight: 700 }}>
                                {col.name}
                              </Typography>
                              <Chip label={tasks.length} size="small" />
                            </Box>

                            {tasks.map((task, index) => {
                              const draggable = canDragTask ? canDragTask(task, currentUser) : false;

                              return (
                                <Draggable key={task.id} draggableId={String(task.id)} index={index} isDragDisabled={!draggable} type="TASK">
                                  {(prov, snap) => (
                                    <Paper
                                      ref={prov.innerRef}
                                      {...prov.draggableProps}
                                      {...prov.dragHandleProps}
                                      elevation={snap.isDragging ? 6 : 2}
                                      sx={{ p: 2, mb: 2, cursor: draggable ? 'grab' : 'default', display: 'flex', alignItems: 'center', gap: 2 }}
                                    >
                                      <Avatar sx={{ width: 36, height: 36 }}>{task.title?.charAt(0)?.toUpperCase() ?? '?'}</Avatar>
                                      <Box sx={{ flex: 1 }}>
                                        <Typography variant="subtitle2" sx={{ fontWeight: 600 }}>
                                          {task.title}
                                        </Typography>
                                        <Typography variant="caption" sx={{ color: '#64748B' }}>
                                          {task.assigned_users?.map((u) => u.name).join(', ')}
                                        </Typography>
                                      </Box>
                                    </Paper>
                                  )}
                                </Draggable>
                              );
                            })}

                            {provided.placeholder}
                          </Paper>
                        )}
                      </Droppable>
                    </div>
                  )}
                </Draggable>
              );
            })}
            {provided.placeholder}
          </Box>
        )}
      </Droppable>
    </DragDropContext>
  );
}
